import { Fragment } from "react"
import type { FsItem } from '$lib/types';
import {
		folderTabActions,
		tabExpandedFolders,
		tabCurrentPath,
		tabViewStyle
	} from '../stores/folderTabStore';
import { directoryTreeCache } from '../utils/directoryTreeCache';
import { ChevronRight, ChevronDown, Loader2 } from 'lucide-react';
import FileItemCard from '$lib/components/panels/file/components/FileItemCard.js';
import { fileBrowserStore } from '$lib/stores/fileBrowser.js';
import { thumbnailManager } from '$lib/utils/thumbnailManager';
interface TreeItem extends FsItem {
		depth: number;
		isExpanded: boolean;
		isLoading: boolean;
	}
interface Props {
		onItemClick?: (item: FsItem) => void | Promise<void>;
		onItemDoubleClick?: (item: FsItem) => void | Promise<void>;
		onItemContextMenu?: (event: MouseEvent, item: FsItem) => void;
	}

export function InlineTreeList(props: Props) {
  const {
		onItemClick = () => {},
		onItemDoubleClick = () => {},
		onItemContextMenu = () => {}
	} = props
  const expandedFolders = tabExpandedFolders;

  const currentPath = tabCurrentPath;

  const viewStyle = tabViewStyle;

  let rootItems = $state<FsItem[]>([]);

  let isLoading = $state(false);

  const childrenCache = new Map<string, FsItem[]>();

  let loadingFolders = $state(new Set<string>());

  let thumbnails = $derived(fileBrowserStore.getState().thumbnails);

  let viewMode = $derived($viewStyle as 'list' | 'content' | 'banner' | 'thumbnail');

  async function loadRootItems(path: string) {
      if (!path) return;

      isLoading = true;
      try {
        // 使用全局目录树缓存
        const items = await directoryTreeCache.getDirectory(path);
        // 排序：文件夹在前
        const sorted = [...items].sort((a, b) => {
          if (a.isDir !== b.isDir) return a.isDir ? -1 : 1;
          return a.name.localeCompare(b.name, undefined, { numeric: true });
        });
        rootItems = sorted;
        // 加载缩略图
        loadThumbnails(sorted, path);
      } catch (err) {
        console.error('[InlineTreeList] Failed to load root:', path, err);
        rootItems = [];
      } finally {
        isLoading = false;
      }
    }

  function loadThumbnails(items: FsItem[], path: string) {
      // 设置当前目录（用于优先级判断）
      thumbnailManager.setCurrentDirectory(path);

      // 过滤出需要缩略图的项目
      const itemsNeedingThumbnails = items.filter((item) => {
        const name = item.name.toLowerCase();
        const isDir = item.isDir;

        // 支持的图片扩展名
        const imageExts = [
          '.jpg',
          '.jpeg',
          '.png',
          '.gif',
          '.bmp',
          '.webp',
          '.avif',
          '.jxl',
          '.tiff',
          '.tif'
        ];
        // 支持的压缩包扩展名
        const archiveExts = ['.zip', '.rar', '.7z', '.cbz', '.cbr', '.cb7'];
        // 支持的视频扩展名
        const videoExts = [
          '.mp4',
          '.mkv',
          '.avi',
          '.mov',
          'nov',
          '.flv',
          '.webm',
          '.wmv',
          '.m4v',
          '.mpg',
          '.mpeg'
        ];

        const ext = name.substring(name.lastIndexOf('.'));

        // 文件夹或支持的文件类型
        return (
          isDir || imageExts.includes(ext) || archiveExts.includes(ext) || videoExts.includes(ext)
        );
      });

      // 预加载数据库索引
      const paths = itemsNeedingThumbnails.map((item) => item.path);
      thumbnailManager.preloadDbIndex(paths).catch((err) => {
        console.debug('预加载数据库索引失败:', err);
      });

      // 为所有项目加载缩略图
      itemsNeedingThumbnails.forEach((item) => {
        if (item.isDir) {
          // 文件夹
          thumbnailManager.getThumbnail(item.path);
        } else {
          // 文件：检查是否为压缩包
          const nameLower = item.name.toLowerCase();
          const isArchive =
            nameLower.endsWith('.zip') ||
            nameLower.endsWith('.cbz') ||
            nameLower.endsWith('.rar') ||
            nameLower.endsWith('.cbr') ||
            nameLower.endsWith('.7z') ||
            nameLower.endsWith('.cb7');

          thumbnailManager.getThumbnail(item.path);
        }
      });
    }

  $effect(() => {
      const path = $currentPath;
      if (path) {
        loadRootItems(path);
      }
    });

  let treeItems = $derived.by(() => {
      const result: TreeItem[] = [];
      const expanded = $expandedFolders;

      function addItems(itemList: FsItem[], depth: number) {
        for (const item of itemList) {
          const isExpanded = item.isDir && expanded.has(item.path);
          const isLoading = loadingFolders.has(item.path);

          result.push({
            ...item,
            depth,
            isExpanded,
            isLoading
          });

          // 如果展开了，添加子项
          if (isExpanded && childrenCache.has(item.path)) {
            const children = childrenCache.get(item.path)!;
            addItems(children, depth + 1);
          }
        }
      }

      addItems(rootItems, 0);
      return result;
    });

  async function loadChildren(path: string) {
      if (childrenCache.has(path)) return;

      loadingFolders = new Set([...loadingFolders, path]);

      try {
        // 使用全局目录树缓存
        const children = await directoryTreeCache.getDirectory(path);
        // 排序：文件夹在前
        const sorted = [...children].sort((a, b) => {
          if (a.isDir !== b.isDir) return a.isDir ? -1 : 1;
          return a.name.localeCompare(b.name, undefined, { numeric: true });
        });
        childrenCache.set(path, sorted);
        // 加载子项的缩略图
        loadThumbnails(sorted, path);
      } catch (err) {
        console.error('[InlineTreeList] Failed to load children:', path, err);
      } finally {
        const newLoading = new Set(loadingFolders);
        newLoading.delete(path);
        loadingFolders = newLoading;
      }
    }

  async function toggleExpand(item: TreeItem) {
      if (!item.isDir) return;

      if (item.isExpanded) {
        folderTabActions.collapseFolder(item.path);
      } else {
        // 先加载子内容
        await loadChildren(item.path);
        folderTabActions.expandFolder(item.path);
      }
    }

  function handleClick(item: TreeItem, event: MouseEvent) {
      // 如果点击的是展开按钮区域，切换展开状态
      const target = event.target as HTMLElement;
      if (target.closest('.expand-btn')) {
        toggleExpand(item);
        return;
      }

      onItemClick?.(item);
    }

  function handleDoubleClick(item: TreeItem) {
      if (item.isDir) {
        toggleExpand(item);
      } else {
        onItemDoubleClick?.(item);
      }
    }

  function handleContextMenu(event: MouseEvent, item: TreeItem) {
      onItemContextMenu?.(event, item);
    }
  return (
    <Fragment>

<div className="inline-tree-list h-full overflow-auto">
	{isLoading ? (<Fragment>
		<div className="flex items-center justify-center py-8">
			<Loader2 className="text-muted-foreground h-6 w-6 animate-spin"></Loader2>
		</div>
	</Fragment>) : (<Fragment>{treeItems.length === 0 ? (<Fragment>
		<div className="text-muted-foreground flex flex-col items-center justify-center py-12 text-center">
			<p>空文件夹</p>
		</div>
	</Fragment>) : (<Fragment>
		{treeItems.map((item) => (<Fragment key={item.path}>
			<div className="tree-item flex items-center" style={`padding-left: ${item.depth * 20}px`}>
				{/*  展开/折叠按钮  */}
				{item.isDir ? (<Fragment>
					<button type="button" className="expand-btn flex h-8 w-6 shrink-0 items-center justify-center" onClick={(e) => {
							e.stopPropagation();
							toggleExpand(item);
						}}>
						{item.isLoading ? (<Fragment>
							<Loader2 className="text-muted-foreground h-4 w-4 animate-spin"></Loader2>
						</Fragment>) : (<Fragment>{item.isExpanded ? (<Fragment>
							<ChevronDown className="text-muted-foreground h-4 w-4"></ChevronDown>
						</Fragment>) : (<Fragment>
							<ChevronRight className="text-muted-foreground h-4 w-4"></ChevronRight>
						</Fragment>)}</Fragment>)}
					</button>
				</Fragment>) : (<Fragment>
					<div className="w-6 shrink-0"></div>
				</Fragment>)}

				{/*  文件项卡片  */}
				<div className="min-w-0 flex-1">
					<FileItemCard item={item} thumbnail={thumbnails.get(item.path.replace(/\\/g, '/'))} viewMode={viewMode} onClick={() => onItemClick?.(item)} onDoubleClick={() => {
							if (item.isDir) {
								toggleExpand(item);
							} else {
								onItemDoubleClick?.(item);
							}
						}} onContextMenu={(e) => onItemContextMenu?.(e, item)}></FileItemCard>
				</div>
			</div>
		</Fragment>))}
	</Fragment>)}</Fragment>)}
</div>

</Fragment>
  )
}
